queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?arrival_hall a :arrival_hall .
    ?arrival_hall p:Arrival_Hall ?arrival_hall2 .
    BIND(?arrival_hall2 AS ?o0)
  }
  UNION
  {
    ?baggage_reclaim a :baggage_reclaim .
    ?baggage_reclaim p:Baggage_Reclaim ?baggage_reclaim2 .
    ?baggage_reclaim p:Maximum_Capacity ?maximum_capacity_f .
    FILTER((STR(?maximum_capacity_f) = "500" || STR(?maximum_capacity_f) = "500.0"))
    BIND(?baggage_reclaim2 AS ?o0)
  }
}

